mapper.select:
SELECT * FROM notification 
WHERE receiver_id = #{receiverId} 
ORDER BY send_time DESC

SELECT * FROM notification 
WHERE receiver_id IS NULL OR receiver_id = #{userId} 
ORDER BY send_time DESC

mapper.insert:
INSERT INTO notification_read_record (notification_id, user_id, read_time, create_time)
VALUES (#{notificationId}, #{userId}, #{readTime}, NOW())
ON DUPLICATE KEY UPDATE read_time = #{readTime}

mapper.select:
SELECT COUNT(*) FROM notification n
WHERE (n.receiver_id IS NULL OR n.receiver_id = #{userId})
AND NOT EXISTS (
    SELECT 1 FROM notification_read_record nrr 
    WHERE nrr.notification_id = n.id AND nrr.user_id = #{userId}
)

